      and q.board_specialty = 'family_medicine'
      and q.scenario = 'ผู้ป่วยอายุ 70 ปี — Na 121, confused; chronic diuretic + SSRI; volume euvolemic by exam; urine Na 65, urine osm 380, serum osm 256'
